SELECT ts_aggr.state, ts_aggr.timestamp AS timestamp, sum(bs_per_bldg.tract_count) AS sample_count, sum(bs_per_bldg.bldg_weight) AS units_count, sum(ts_aggr._inner_rows) / CAST(count(distinct(ts_aggr.bldg_id)) AS DECIMAL) AS rows_per_sample, sum(ts_aggr.bs__elec_minus_gas * bs_per_bldg.bldg_weight) AS elec_minus_gas FROM (SELECT ts_flat.timestamp AS timestamp, ts_flat.bldg_id AS bldg_id, ts_flat.state AS state, sum(ts_flat._v__elec_minus_gas) AS bs__elec_minus_gas, count(*) AS _inner_rows FROM (SELECT resstock_2024_amy2018_release_2_by_state_vu.bldg_id AS bldg_id, date_trunc('month', date_add('second', -900, resstock_2024_amy2018_release_2_by_state_vu.timestamp)) AS timestamp, resstock_2024_amy2018_release_2_by_state_vu.state AS state, resstock_2024_amy2018_release_2_by_state_vu."out.electricity.total.energy_consumption" - resstock_2024_amy2018_release_2_by_state_vu."out.natural_gas.total.energy_consumption" AS _v__elec_minus_gas FROM resstock_2024_amy2018_release_2_by_state_vu WHERE resstock_2024_amy2018_release_2_by_state_vu.upgrade IN (1) AND resstock_2024_amy2018_release_2_by_state_vu.state = 'CO') AS ts_flat GROUP BY ts_flat.timestamp, ts_flat.bldg_id, ts_flat.state) AS ts_aggr JOIN (SELECT bs.bldg_id AS bldg_id, sum(bs.weight) AS bldg_weight, count(*) AS tract_count FROM resstock_2024_amy2018_release_2_metadata AS bs WHERE bs.upgrade = 0 AND bs."in.state" = 'CO' GROUP BY bs.bldg_id) AS bs_per_bldg ON bs_per_bldg.bldg_id = ts_aggr.bldg_id GROUP BY 1, 2 ORDER BY 1, 2